INSERT INTO `email_templates` VALUES (1,'REPLY_INTENT','Reply to Letter of Intent','TAU-REO: Application Requirements','Greetings from TAU-REO!\r\n\r\nPlease read the general guidelines for research ethics review and evaluation. Then, kindly accomplish the following documents:\r\n\r\n✓ Application form TAU-REO-QF-01 (see attached file)\r\n✓ Research Ethics Review Category Form TAU-REO-QF-02 (see attached file)\r\n✓ CV of proponents\r\n✓ Research proposal/Thesis/Dissertation Outline\r\n\r\nSend the digital copy of the fully accomplished documents through this portal. As you upload the requirements, please ensure all forms are properly filled and signed. Thank you.\r\n\r\nPlease take note of the following:\r\n\r\n* Do not change the format and font style of the ISO registered forms\r\n* Please fill out the forms completely before uploading\r\n* Please be guided with our process cycle time (see the General Guidelines for more info). We process applications during working days only.\r\n\r\nBest regards,\r\nTAU-REO','Initial response to letter of intent submission','review_process','[\"{{applicant_name}}\", \"{{queue_number}}\"]',1,'2026-02-03 01:20:42','2026-02-09 05:33:04'),(2,'ACK_COMPLETE','Acknowledgment of Complete Submission','TAU-REO: Documents Received','<p>Greetings from TAU-REO!</p>\n\n<p>We acknowledge with appreciation the receipt of your complete documents. Your submission will now undergo evaluation to determine the appropriate Research Ethics Review Category.</p>\n\n<p>Kindly wait for further updates regarding the review process. Should you have any questions, feel free to reach out.</p>\n\n<p>Thank you.</p>\n\n<p>--Best regards,<br>\nTAU-REO</p>','Acknowledgment when all required documents are submitted','review_process','[\"{{applicant_name}}\", \"{{queue_number}}\"]',1,'2026-02-03 01:20:42','2026-02-03 01:20:42'),(3,'INCOMPLETE_DOCS','Incomplete Documents Notice','TAU-REO: Incomplete Submission','<p>Good day!</p>\n\n<p>We have reviewed your submission for ethics review, and we have identified missing/incomplete documents required for processing your application. Kindly provide the following documents at your earliest convenience:</p>\n\n<p>{{missing_documents}}</p>\n\n<p>Thank you very much.</p>\n\n<p>--Best regards,<br>\nTAU-REO</p>','Notification when documents are missing or incomplete','review_process','[\"{{applicant_name}}\", \"{{queue_number}}\", \"{{missing_documents}}\"]',1,'2026-02-03 01:20:42','2026-02-03 01:20:42'),(4,'MISSING_SIGNATURES','Missing Signatures Notice','TAU-REO: Missing Signatures','<p>Good day!</p>\n\n<p>We have reviewed your submission for ethics review and found that some required signatures are missing. To proceed with the review, kindly ensure that the following documents are duly signed:</p>\n\n<p>{{unsigned_documents}}</p>\n\n<p>Thank you very much.</p>\n\n<p>--Best regards,<br>\nTAU-REO</p>','Notification when required signatures are missing','review_process','[\"{{applicant_name}}\", \"{{queue_number}}\", \"{{unsigned_documents}}\"]',1,'2026-02-03 01:20:42','2026-02-03 01:20:42'),(5,'APPROVED','Application Approved','TAU-REO: Application Approved','<p>Dear {{applicant_name}},</p>\n\n<p>We are pleased to inform you that your research ethics application <strong>({{queue_number}})</strong> has been <strong>APPROVED</strong>.</p>\n\n<p>\n<strong>Category:</strong> {{category}}<br>\n<strong>Approval Date:</strong> {{approval_date}}\n</p>\n\n<p>You may now proceed with your research as outlined in your approved proposal. Please ensure that you adhere to all ethical guidelines and protocols throughout your study.</p>\n\n<p>Should you need any certificates or have any questions, please feel free to contact us.</p>\n\n<p><strong>Congratulations!</strong></p>\n\n<p>--Best regards,<br>\nTAU-REO</p>','Approval notification email','decision','[\"{{applicant_name}}\", \"{{queue_number}}\", \"{{category}}\", \"{{approval_date}}\"]',1,'2026-02-03 01:20:42','2026-02-03 01:20:42'),(6,'CONDITIONAL_APPROVAL','Conditional Approval','TAU-REO: Conditional Approval','<p>Dear {{applicant_name}},</p>\n\n<p>Your research ethics application <strong>({{queue_number}})</strong> has been given <strong>CONDITIONAL APPROVAL</strong>.</p>\n\n<p><strong>Category:</strong> {{category}}</p>\n\n<p>The following conditions must be addressed before final approval:</p>\n\n<p>{{conditions}}</p>\n\n<p>Please submit the required revisions at your earliest convenience. Once all conditions are satisfactorily met, final approval will be granted.</p>\n\n<p>--Best regards,<br>\nTAU-REO</p>','Conditional approval with required modifications','decision','[\"{{applicant_name}}\", \"{{queue_number}}\", \"{{category}}\", \"{{conditions}}\"]',1,'2026-02-03 01:20:42','2026-02-03 01:20:42'),(7,'REJECTED','Application Rejected','TAU-REO: Application Not Approved','<p>Dear {{applicant_name}},</p>\n\n<p>We regret to inform you that your research ethics application <strong>({{queue_number}})</strong> has <strong>NOT been approved</strong> at this time.</p>\n\n<p><strong>Reason:</strong></p>\n<p>{{rejection_reason}}</p>\n\n<p>You may resubmit your application after addressing the concerns raised. Should you need clarification or guidance, please feel free to contact our office.</p>\n\n<p>--Best regards,<br>\nTAU-REO</p>','Rejection notification email','decision','[\"{{applicant_name}}\", \"{{queue_number}}\", \"{{rejection_reason}}\"]',1,'2026-02-03 01:20:42','2026-02-03 01:20:42'),(8,'REVISIONS_NEEDED','Revisions Required','TAU-REO: Revisions Needed','<p>Dear {{applicant_name}},</p>\n\n<p>Thank you for your submission <strong>({{queue_number}})</strong>. After careful review, we require some revisions to your application before we can proceed with the evaluation.</p>\n\n<p><strong>Required revisions:</strong></p>\n<p>{{revisions_list}}</p>\n\n<p>Please resubmit your revised documents at your earliest convenience. If you have any questions about the required changes, please do not hesitate to contact us.</p>\n\n<p>--Best regards,<br>\nTAU-REO</p>','Request for revisions or clarifications','review_process','[\"{{applicant_name}}\", \"{{queue_number}}\", \"{{revisions_list}}\"]',1,'2026-02-03 01:20:42','2026-02-03 01:20:42'),(9,'CERTIFICATE_ISSUED','Certificate Issued','TAU-REO: Ethics Clearance Certificate','<p>Dear {{applicant_name}},</p>\n\n<p>Your <strong>Ethics Clearance Certificate</strong> has been issued for your approved research project.</p>\n\n<p>\n<strong>Certificate Number:</strong> {{certificate_number}}<br>\n<strong>Valid Until:</strong> {{valid_until}}<br>\n<strong>Queue Number:</strong> {{queue_number}}\n</p>\n\n<p>Please find the certificate attached to this email. Keep this certificate for your records and present it when required.</p>\n\n<p>--Best regards,<br>\nTAU-REO</p>','Certificate issuance notification','certificate','[\"{{applicant_name}}\", \"{{queue_number}}\", \"{{certificate_number}}\", \"{{valid_until}}\"]',1,'2026-02-03 01:20:42','2026-02-03 01:20:42'),(10,'GENERAL_UPDATE','General Update','TAU-REO: Application Update','<p>Dear {{applicant_name}},</p>\n\n<p>We would like to provide you with an update regarding your application <strong>({{queue_number}})</strong>.</p>\n\n<p>{{message_content}}</p>\n\n<p>If you have any questions or concerns, please feel free to reach out to us.</p>\n\n<p>--Best regards,<br>\nTAU-REO</p>','General purpose update template','general','[\"{{applicant_name}}\", \"{{queue_number}}\", \"{{message_content}}\"]',1,'2026-02-03 01:20:42','2026-02-03 01:20:42');
/*!40000 ALTER TABLE `email_templates` ENABLE KEYS */;

