  CONSTRAINT `fillable_forms_ibfk_1` FOREIGN KEY (`queue_number`) REFERENCES `applications` (`queue_number`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=32 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
