INSERT INTO `fillable_forms` VALUES (5,'UREO-0001','qf02','{\"title\": \"AGRICULTURAL INFORMATION ACCESS AND COMMUNICATION CHALLENGES OF BRGY. GOSSOOD FARMERS: BASIS FOR DEVELOPING EFFECTIVE IEC MATERIAL\", \"crit_3_no\": \"on\", \"crit_6_no\": \"on\", \"crit_7_no\": \"on\", \"crit_8_no\": \"on\", \"crit_9_no\": \"on\", \"crit_10_no\": \"on\", \"crit_11_no\": \"on\", \"crit_12_no\": \"on\", \"crit_13_no\": \"on\", \"crit_16_no\": \"on\", \"crit_18_no\": \"on\", \"crit_19_no\": \"on\", \"crit_1_yes\": \"on\", \"crit_20_no\": \"on\", \"crit_2_yes\": \"on\", \"crit_4_yes\": \"on\", \"crit_5_yes\": \"on\", \"crit_14_yes\": \"on\", \"crit_15_yes\": \"on\", \"crit_17_yes\": \"on\", \"date_filled\": \"2025-02-25\", \"date_signed\": \"2025-02-24\", \"adviser_name\": \"Nelmar A. Mallari, LPT, MDC\", \"participants\": \"\", \"crit_1_remarks\": \"\", \"crit_2_remarks\": \"\", \"crit_3_remarks\": \"\", \"crit_4_remarks\": \"\", \"crit_5_remarks\": [{\"role\": \"staff\", \"text\": \"The study involves an interview which require informed consent.\", \"timestamp\": \"Legacy\"}, {\"role\": \"staff\", \"text\": \"The study involves an interview which require informed consent.\", \"user_id\": 2, \"timestamp\": \"2026-04-21 08:29:38\"}], \"crit_6_remarks\": \"\", \"crit_7_remarks\": \"\", \"crit_8_remarks\": \"\", \"crit_9_remarks\": \"\", \"proponent_name\": \"Christian H. Gabriel\", \"crit_10_remarks\": \"\", \"crit_11_remarks\": \"\", \"crit_12_remarks\": \"\", \"crit_13_remarks\": \"\", \"crit_14_remarks\": [{\"role\": \"staff\", \"text\": \"Involvement of microorganisms was not specified\", \"timestamp\": \"Legacy\"}, {\"role\": \"staff\", \"text\": \"Involvement of microorganisms was not specified\", \"user_id\": 2, \"timestamp\": \"2026-04-21 08:29:38\"}], \"crit_15_remarks\": \"\", \"crit_16_remarks\": \"\", \"crit_17_remarks\": [{\"role\": \"staff\", \"text\": \"The study does not involve digital tools for data collection and storage.\", \"timestamp\": \"Legacy\"}, {\"role\": \"staff\", \"text\": \"The study does not involve digital tools for data collection and storage.\", \"user_id\": 2, \"timestamp\": \"2026-04-21 08:29:38\"}], \"crit_18_remarks\": \"\", \"crit_19_remarks\": \"\", \"crit_20_remarks\": \"\"}','2026-04-21 00:29:38',1,0,NULL,0,0,NULL),(6,'UREO-0001','qf01','{\"email\": \"gc_hida2021@tau.edu.ph\", \"phone\": \"09383797173\", \"it_use\": \"☐\", \"funding\": \"N/A\", \"members\": \"Allen John Agcang\\r\\nCharles Ramiento\", \"duration\": \"Second semester A.Y. 2024-2025\", \"end_date\": \"2025-04-22\", \"location\": \"This study will be conducted in Brgy. Gossood, a rural community in Mayantoc, Tarlac. Located in a mountainous and highland area.\", \"food_tech\": \"☐\", \"human_use\": \"☑\", \"plant_use\": \"☐\", \"review_no\": \"☑\", \"department\": \"College of Arts and Sciences\", \"human_role\": \"In order to initiate an interview with the target community, once the researchers will be secure  to obtain the approval of the college dean through a letter. The letter is approved, the researchers will present the letter to the authority of the chairman of the barangay. For a step for the conduct and endorsement from the approval of the chairman the researchers will coordinate with the participants and build connections to agree on the convenient schedule for an interview. \\r\\nEthical considerations are a cornerstone of this study to ensure the protection and respect of all participants involved. Informed consent will be obtained from each participant, ensuring they are fully aware of the study purpose, their rights, and the voluntary nature of their participation. Prior to engaging in surveys, and interviews, participants will be provided with clear and comprehensive information about the research. Confidentiality will be strictly maintained throughout the process; all personal identifiers will be anonymized, and participants\' responses will be stored securely to prevent unauthorized access. Furthermore, participants will be assured that their involvement is voluntary, and they have the right to withdraw from the study at any point without any adverse consequences. These ethical guidelines are essential for maintaining the integrity of the research and protecting the welfare of the participants.\\r\\nIn the administered data gathering procedure, the semi constructed interview will take place in the homes of the selected participants. This choice of the venue of the researchers to ensure the comfort of the involved participants in their environment. In the conduct of the interview the participants are highly encouraged to share their experience and knowledge of practices using the given prepared questions.  These open ended questions covered the various facets of their practices, knowledge, coping strategies and their perceptions regarding the factors of communication approach in the capabilities of farmers to their community. To stabilize the accuracy and the comprehensiveness of the collecting data. This process is crucial for later analysis, the approach stands a chance and ultimately makes the study results more reliable. In essence, The approach goes beyond data collection and it is a dialogue, a shared exploration, and a commitment to understanding the human story behind the answers and by the weaving of voices, experiences, and wisdom of the participants into the fabric of the research, the study aspires to create outcomes that can utilize to create solution that are not only reliable but also deeply relevant, actionable, and rooted in the community’s lived realities. \", \"review_yes\": \"☐\", \"start_date\": \"2024-09-01\", \"attached_cv\": \"☑\", \"date_filled\": \"2025-02-24\", \"date_signed\": \"2025-02-24\", \"engineering\": \"☐\", \"adviser_name\": \"Nelmar A. Mallari, LPT, MDC\", \"exec_summary\": \"This research is driven by the need to understand the socio-economic and environmental conditions of these farmers in depth. By investigating their experiences with key agricultural challenges, this study aims to generate insights that can directly inform the creation of communication materials tailored to the unique needs of Brgy. Gossood farmers. Effective communication plays a crucial role in bridging the gap between farmers and relevant support systems, including government agencies, agricultural cooperatives, and technology providers. Hence, this study aims to not only explore the existing challenges but also identify appropriate channels and formats for delivering useful farming information. Understanding the context of the locality and the farming challenges faced will allow for the development of communication materials that are both relevant and accessible to the farmers. \", \"microbio_use\": \"☐\", \"adviser_email\": \"\", \"justification\": \"This study will adopt a descriptive mixed-method research design, combining quantitative and qualitative approaches. Through this research design, the researchers will analyze the resources, perceptions, challenges and effects in order to ensure the comprehensive understanding of the issue at hand in providing effective communication strategy for agricultural information dissemination. It involves philosophical assumptions, and the mixing of qualitative and quantitative approaches in tandem so that the overall strength of a study is greater than either qualitative or quantitative methods (Creswell, 2007). The descriptive design will help analyze the sources, perceptions, challenges, and effects of agricultural information dissemination, while the mixed-methods approach will ensure a comprehensive understanding of the communication needs of Brgy. Gossood farmers. Additionally, the mixed method approach ensures to elaborate comprehensive and effective IEC materials that are specially tailored concerning the Mayantoc farmers. The study will collect detailed information through accessing, understanding and applying agricultural information to deep seek and highlight the decision making in their agricultural practices in touch of traditional and modern farming practices in Brgy. Gossood. Moreover, to categorize and identify the communication materials that can be effectively used as strategy within addressing the gaps in disseminating agricultural information and valuable government information in Brgy. Gossood farmers.\", \"pilot_or_part\": \"\", \"project_title\": \"AGRICULTURAL INFORMATION ACCESS AND COMMUNICATION CHALLENGES OF BRGY. GOSSOOD FARMERS: BASIS FOR DEVELOPING EFFECTIVE IEC MATERIAL\", \"review_status\": \"Not yet\", \"animal_welfare\": \"☐\", \"principal_name\": \"Christian Gabriel\", \"requestor_name\": \"CHRISTIAN H. GABRIEL\", \"attached_outline\": \"☑\", \"problem_objectives\": \"This study aims to explore the accessibility-capability of Brgy. Gossood, Mayantoc farmers to agricultural information as well as to the challenges they face as a basis for creating effective information, education, communication (IEC) materials. Specifically, it seeks to address the following questions:\\r\\n\\r\\n1. What are the primary sources of agricultural information accessed by farmers in Brgy. Gossood?\\r\\n2. How do farmers perceive the effectiveness of existing agricultural communication strategies in Brgy. Gossood in terms of:\\r\\nAccessibility; and\\r\\ndissemination?\\r\\n3. What challenges do Brgy. Gossood farmers face in terms of:\\r\\naccessing;\\r\\nunderstanding; and\\r\\napplying agricultural information?\\r\\n4. What extent does the dissemination of agri info influence the farmers in terms of their:\\r\\n decision-making in farm practices\\r\\n access to government support systems\\r\\n5. What type of communication material can be developed to address the identified gaps in agricultural information dissemination?\", \"attached_other_forms\": \"☐\", \"attached_consent_form\": \"☑\", \"attached_category_form\": \"☑\", \"data_collection_analysis\": \"\"}','2026-02-16 01:43:43',1,0,NULL,0,0,NULL),(10,'UREO-0002','qf02','{\"title\": \"DETECTION OF HEARTWORM (Dirofilaria immitis) IN DOGS USING RAPID IMMUNOCHROMATOGRAPHIC ASSAY (CHW Ag) AT BARANGAY SAPANG MARAGUL, TARLAC CITY\", \"crit_2_no\": \"on\", \"crit_3_no\": \"on\", \"crit_4_no\": \"on\", \"crit_8_no\": \"on\", \"crit_10_no\": \"on\", \"crit_11_no\": \"on\", \"crit_12_no\": \"on\", \"crit_13_no\": \"on\", \"crit_14_no\": \"on\", \"crit_15_no\": \"on\", \"crit_16_no\": \"on\", \"crit_17_no\": \"on\", \"crit_18_no\": \"on\", \"crit_19_no\": \"on\", \"crit_1_yes\": \"on\", \"crit_20_no\": \"on\", \"crit_5_yes\": \"on\", \"crit_6_yes\": \"on\", \"crit_7_yes\": \"on\", \"crit_9_yes\": \"on\", \"date_filled\": \"2025-03-03\", \"date_signed\": \"2025-03-03\", \"adviser_name\": \"ANNALIE B. PARAGAS, DVM, MSAH\", \"participants\": \"DOGS AND DOG OWNERS\", \"proponent_name\": \"PRINCESS T. CABENTA\"}','2026-02-16 03:42:57',1,0,NULL,0,0,NULL),(11,'UREO-0002','qf01','{\"email\": \"ptcabenta@tau.edu.ph\", \"phone\": \"09947638158\", \"it_use\": \"☐\", \"funding\": \"N/A\", \"members\": \"\", \"duration\": \"2 Months\", \"end_date\": \"2025-06-19\", \"location\": \"This study will be conducted in Barangay Sapang Maragul, Tarlac City, which consists of seven sitios: Bagong Barrio Resettlement, Bagong Diwa, Bungil, Carague, Centro, Kumintang, and Samberga. The area\'s geography, including creeks, seasonal flooding, and stagnant water, provides an ideal breeding ground for mosquitoes, increasing the risk of heartworm transmission in dogs.\", \"food_tech\": \"☐\", \"human_use\": \"☐\", \"plant_use\": \"☐\", \"review_no\": \"☑\", \"department\": \"TARLAC AGRICULTURAL UNIVERSITY - COLLEGE OF VETERINARY MEDICINE\", \"human_role\": \"The subjects of this study will be dogs residing in the selected sitios of Barangay Sapang Maragul. These dogs will be tested for Dirofilaria immitis using a rapid immunochromatographic assay (CHW Ag). Dog owners will also participate by providing relevant information about their pets and management practices through surveys.\", \"review_yes\": \"☐\", \"start_date\": \"2025-04-01\", \"attached_cv\": \"☑\", \"date_filled\": \"2025-03-03\", \"date_signed\": \"2025-03-03\", \"engineering\": \"☐\", \"adviser_name\": \"ANNALIE B. PARAGAS\", \"exec_summary\": \"Heartworm disease (Dirofilaria immitis) is a serious and potentially fatal condition in dogs, primarily transmitted through mosquito bites. It affects the heart, lungs, and blood vessels, leading to severe complications if left untreated. The disease is prevalent in areas with high mosquito populations, and its spread is influenced by environmental factors such as temperature and humidity. Despite the availability of preventive measures, many pet owners remain unaware of the risks and the importance of early detection.\\r\\n\\r\\nThis study is necessary to assess the prevalence of heartworm in dogs in the sitios of Barangay Sapang Maragul, Tarlac City. By using a rapid immunochromatographic assay (CHW Ag), the research aims to provide baseline data on the presence of heartworm in the area. Identifying risk factors and evaluating management practices among dog owners will help develop targeted interventions for disease prevention.  \\r\\n\\r\\nThe findings of this study will contribute to veterinary health by raising awareness among pet owners and veterinarians in implementing effective prevention and control measures. By improving early detection and responsible pet care, this research seeks to reduce the prevalence of heartworm disease and promote better animal health and welfare in the community.\", \"microbio_use\": \"☐\", \"adviser_email\": \"\", \"justification\": \"Detection of Heartworm (Dirofilaria immitis) in dogs\", \"pilot_or_part\": \"Whether the study to be reviewed is a pilot study or a continuation of previous completed study or part of a larger study/project. If it is part of a larger project, describe briefly the rationale and objectives of the whole project.\", \"project_title\": \"DETECTION OF HEARTWORM (Dirofilaria immitis) IN DOGS USING RAPID IMMUNOCHROMATOGRAPHIC ASSAY (CHW Ag) AT BARANGAY SAPANG MARAGUL, TARLAC CITY\", \"review_status\": \"\", \"animal_welfare\": \"☑\", \"principal_name\": \"PRINCESS T. CABENTA\", \"requestor_name\": \"PRINCESS T. CABENTA\", \"attached_outline\": \"☑\", \"problem_objectives\": \"This study aims to assess the prevalence of heartworm in selected dogs in the sitios of Sapang Maragul using a rapid immunochromatographic assay (CHW Ag). Specifically, it seeks to determine the signalment of dogs and owners\' management practices in Barangay Sapang Maragul, Tarlac City, Tarlac; detect heartworm infestation in dogs using a one-way test kit in the sitios of Barangay Sapang Maragul, Tarlac City, Tarlac; assess the occurrence of canine heartworm in the area; determine the possible risk factors that contribute to heartworm infection in dogs; and create awareness campaign materials/IEC on the prevalence of heartworm.\", \"attached_other_forms\": \"☐\", \"attached_consent_form\": \"☐\", \"attached_category_form\": \"☑\", \"data_collection_analysis\": \"Blood samples will be collected from selected dogs in the morning (5:00–7:00 AM) or late in the afternoon (5:00–7:00 PM). Dogs will be restrained, muzzled if necessary, and the cephalic vein will be disinfected before drawing 1 mL of blood using a 3 mL syringe. The site will be pressed with a cotton ball and secured with micropore tape. Samples will be stored in labeled EDTA tubes, placed in an ice box with ice gel, and transported to the Central Laboratory of the College of Veterinary Medicine, Tarlac Agricultural University, for antigen testing using VET Diagnostix Rapid Test Kits.\\r\\nThe study will collect data on the dog population, profiles, owner management practices, and heartworm test results. A questionnaire will be used for additional information. Data will be analyzed using descriptive statistics (mean, frequency, percentage) and correlated with the dogs’ demographics and history.\"}','2026-02-16 03:54:09',1,0,NULL,0,0,NULL),(23,'UREO-0001','category_token','{\"token\": \"f92044410d61b2a0772949e7d19f53c2\", \"category\": \"human\", \"expires_at\": \"2026-04-14 15:52:44\", \"review_type\": \"expedited\"}','2026-04-07 07:52:44',1,0,NULL,0,0,NULL),(24,'UREO-0001','category_checklist','{\"h_end\": \"2025-04-22\", \"h_email\": \"gc_hida2021@tau.edu.ph\", \"h_phone\": \"09383797173\", \"h_start\": \"2024-09-01\", \"h_title\": \"AGRICULTURAL INFORMATION ACCESS AND COMMUNICATION CHALLENGES OF BRGY. GOSSOOD FARMERS: BASIS FOR DEVELOPING EFFECTIVE IEC MATERIAL\", \"h_course\": \"\", \"h_adviser\": \"Nelmar A. Mallari, LPT, MDC\", \"h_members\": \"Allen John Agcang\\r\\nCharles Ramiento\", \"h_objective\": \"test\", \"h_principal\": \"Christian Gabriel\", \"h_sign_name\": \"Christian Gabriel\", \"queue_number\": \"UREO-0001\", \"submitted_at\": \"2026-04-08 14:59:27\", \"h_affiliation\": \"College of Arts and Sciences\", \"h_date_filled\": \"\", \"h_date_signed\": \"\", \"classification\": \"human\", \"h_adviser_email\": \"\", \"h_adviser_phone\": \"\", \"h_adviser_sign_name\": \"Nelmar A. Mallari, LPT, MDC\", \"h_adviser_affiliation\": \"\"}','2026-04-08 06:59:27',1,0,NULL,0,0,NULL),(27,'UREO-0003','qf02','{\"title\": \"Adaptive Capacity Of Different Varieties and Establishment Methods As Means Of Tecnological Adaptation To Rainfed Rice Production In Camiling, Tarlac\", \"crit_2_no\": \"on\", \"crit_4_no\": \"on\", \"crit_6_no\": \"on\", \"crit_7_no\": \"on\", \"crit_8_no\": \"on\", \"crit_9_no\": \"on\", \"crit_12_no\": \"on\", \"crit_13_no\": \"on\", \"crit_14_no\": \"on\", \"crit_16_no\": \"on\", \"crit_18_no\": \"on\", \"crit_19_no\": \"on\", \"crit_1_yes\": \"on\", \"crit_20_no\": \"on\", \"crit_3_yes\": \"on\", \"crit_5_yes\": \"on\", \"crit_10_yes\": \"on\", \"crit_11_yes\": \"on\", \"crit_15_yes\": \"on\", \"crit_17_yes\": \"on\", \"date_filled\": \"2025-02-24\", \"date_signed\": \"2025-03-02\", \"adviser_name\": \"Joyce Anne O. Manuel\", \"participants\": \"Rainfed Farmers, Different Rice Varieties\", \"proponent_name\": \"Desiree Joi D. Duque\"}','2026-04-16 07:10:16',0,0,NULL,0,0,NULL),(28,'UREO-0004','qf02','{\"title\": \"Test\", \"crit_5_no\": \"on\", \"crit_1_yes\": \"on\", \"crit_2_yes\": \"on\", \"crit_4_yes\": \"on\", \"date_filled\": \"2026-05-19\", \"date_signed\": \"2026-05-19\", \"adviser_name\": \"Noel J. Petero, Ph.D.\", \"participants\": \"\", \"proponent_name\": \"Robertlyn Geil Soriano\"}','2026-05-19 03:57:21',0,0,NULL,0,0,NULL),(29,'UREO-0003','qf01','{\"email\": \"example@gmail.com\", \"phone\": \"09123456789\", \"it_use\": \"☐\", \"funding\": \"N/A\", \"members\": \"Regine G. Batin, Desiree Joi D. Duque, Jhanny D. Tejada, Jhon Carlo G. Valdez\", \"duration\": \"7 months\", \"end_date\": \"2026-10-26\", \"location\": \"The study will be conducted in Caniag, Camiling, Tarlac.\", \"food_tech\": \"☐\", \"human_use\": \"☑\", \"plant_use\": \"☑\", \"review_no\": \"☑\", \"department\": \"College of Agriculture and Forestry\", \"human_role\": \"Rainfed Farmers – the rainfed farmers will give us information about what are the rice varieties they plant in their field, what are the establishment methods they use in farming, the equipment and implements they used in land preparation and their cost and return analysis.\\r\\nPlants – the different varieties of rice are used to evaluate their adaptability on different establishment methods that can influence their productivity.\", \"review_yes\": \"☐\", \"start_date\": \"2026-03-26\", \"attached_cv\": \"☑\", \"date_filled\": \"2026-05-26\", \"date_signed\": \"2026-05-26\", \"engineering\": \"☐\", \"adviser_name\": \"JOYCE ANNE O. MANUEL\", \"exec_summary\": \"Rice (Oryza sativa L.) is the major food of about half of the world’s population, mostly in Asia (MacLean et al., 2002). Estimated about 90% of the world’s rice are produced and consumed in Asia. Water is vital in food security. The availability of water resources and quality greatly affect agricultural land use (Luyun, 2015). Rainfall is an important water resource, but it is unpredictable (NWRB-PNRI 2012). The challenge of climate change combined with a decrease in rainfall there can be severe water stress that causes significant yield reduction (Luyun, 2015). Eighty percent of the world is practiced in rainfed agriculture and it contributes 62% of the world’s staple food (Rockstrom et al., 2007; FAOSTAT, 2011). The common practice on rice cultivation in Southeast Asia is conventional transplanting, therefore this type of establishing method need high water inputs (Sangeetha & Baskar, 2015). Adoption of different water-saving technologies that requires less irrigation input while enhancing production is possible. In dry seeding, the amount of water needed for rice establishment can be reduced (Cabangon et al., 2015). A dry-seeded crop production gives a high return at lower costs (Rahman, 2016). Also, to increase yields and improve productivity especially in rainfed area, we can use flexible, high-yielding varieties (Rahman & Connor,\\r\\n2022) that will go a long way in guaranteeing the nation’s food security. Adopting other varieties and\\r\\ndifferent establishment method that can be used to mitigate the effect of the different climate conditions is important in rainfed areas. This study aims to evaluate the adaptive capacity of different varieties and\\r\\nestablishment methods as means of technological adaptation to rainfed rice production in Camiling, Tarlac,\\r\\nwhere water scarcity due to the effect of climate change is one of the key problems in the area.\", \"microbio_use\": \"☐\", \"adviser_email\": \"example1@gmail.com\", \"justification\": \"Water is vital in food security. The availability of water resources and quality greatly affect agricultural land use (Luyun, 2015). Rainfall is an important water resource, but it is unpredictable (NWRB-PNRI 2012). The challenge of climate change combined with a decrease in rainfall there can be severe water stress that causes significant yield reduction (Luyun, 2015). Eighty percent of the world is practiced in rainfed agriculture and it contributes 62% of the world’s staple food (Rockstrom et al., 2007; FAOSTAT, 2011). Adoption of different water-saving technologies that requires less irrigation input while enhancing production is possible. Adopting other varieties and different establishment method that can be used to mitigate the effect of the different climate conditions is important in rainfed areas. This study aims to evaluate the adaptive capacity of different varieties and establishment methods as means of technological adaptation to rainfed rice production in Camiling, Tarlac, where water scarcity due to the effect of climate change is one of the key problems in the area.\", \"pilot_or_part\": \"\", \"project_title\": \"Adaptive Capacity Of Different Varieties and Establishment Methods As Means Of Tecnological Adaptation To Rainfed Rice Production In Camiling, Tarlac\", \"review_status\": \"\", \"animal_welfare\": \"☐\", \"principal_name\": \"Desiree Joi D. Duque\", \"requestor_name\": \"Desiree Joi D. Duque\", \"attached_outline\": \"☑\", \"problem_objectives\": \"The study generally aims to evaluate the adaptive capacity of different varieties and establishment\\r\\nmethods as a means of technological adaptation to rainfed rice production in Camiling, Tarlac.\\r\\nSpecifically, Study 1 aims to:\\r\\n1. Identify the rice establishment methods commonly practiced by farmers in rainfed areas in\\r\\nCamiling, Tarlac.\\r\\n2. Identify the most common varieties used by the farmers in rainfed areas in Camiling, Tarlac.\\r\\n3. Assess the profitability of producing rice under rainfed conditions using different varieties and rice\\r\\nestablishment methods.\\r\\nWhile Study 2 specifically aims to:\\r\\n1. Evaluate the growth and yield performance of different varieties under rainfed conditions in\\r\\nCamiling, Tarlac.\\r\\n2. Evaluate the effect of different rice establishment methods on the growth and yield of rice under\\r\\nrainfed condition.\\r\\n3. Evaluate the adaptive capacity of different varieties and rice establishment methods as a means of\\r\\ntechnological adaptation to rainfed rice (Oryza sativa L.) production in Camiling, Tarlac.\\r\\n4. Assess the profitability of producing rice under rainfed conditions using different varieties and rice\\r\\nestablishment methods.\", \"attached_other_forms\": \"☐\", \"attached_consent_form\": \"☐\", \"attached_category_form\": \"☑\", \"data_collection_analysis\": \"For study 1, the researchers will send a communication letter to the Municipal Mayor of Camiling, office of the Municipal Agriculture, and three (3) Barangay Captains of Bilad, Caniag, and Carael. Moreover, a courtesy call will be conducted with the above-mentioned officials to inform them about the data gathering activities in their municipalities. Data will be collected, summarized, and tabulated, using frequency distribution. Data on corresponding percentages will be graphical representations.\\r\\n- For study 2, The data to be gathered are as follows:\\r\\n1. Plant Height at Maturity (cm)\\r\\n2. Panicle Length at Maturity (cm)\\r\\n3. Number of Productive Tillers\\r\\n4. Number of Non- Productive Tillers\\r\\n5. Number of Filled Grains per Panicle\\r\\n6. Number of Unfilled Grains per Panicle\\r\\n7. Number of Grains per Panicle\\r\\n8. Weight of 1000 Grains Corrected at 14% MC\\r\\n9. Yield per Plot\\r\\n10. Computed Grain Yield per Hectare (ton/ha)\\r\\nData will be analyzed using the open-source software Statistical Tool for Agricultural Research (STAR) ver. 2.0 (IRRI, 2022) using Analysis of Variance (ANOVA) in Split Plot-Randomized Complete Block Design (RCBD). Treatment means having significant or highly significant results will be compared using the Least Significant Difference (LSD) Test.\"}','2026-05-26 02:07:24',1,0,NULL,0,0,NULL),(30,'UREO-0003','category_checklist','{\"p2_no\": \"on\", \"p3_no\": \"on\", \"p4_no\": \"on\", \"p5_no\": \"on\", \"p6_no\": \"on\", \"p7_no\": \"on\", \"p8_no\": \"on\", \"p9_no\": \"on\", \"p_end\": \"2026-10-26\", \"p10_no\": \"on\", \"p11_no\": \"on\", \"p12_no\": \"on\", \"p13_no\": \"on\", \"p14_no\": \"on\", \"p15_no\": \"on\", \"p16_no\": \"on\", \"p17_no\": \"on\", \"p18_no\": \"on\", \"p19_no\": \"on\", \"p1_yes\": \"on\", \"p20_no\": \"on\", \"p21_no\": \"on\", \"p22_no\": \"on\", \"p23_no\": \"on\", \"p24_no\": \"on\", \"p25_no\": \"on\", \"p26_no\": \"on\", \"p27_no\": \"on\", \"p28_no\": \"on\", \"p29_no\": \"on\", \"p30_no\": \"on\", \"p31_no\": \"on\", \"p32_no\": \"on\", \"p33_no\": \"on\", \"p34_no\": \"on\", \"p35_no\": \"on\", \"p8_ifno\": \"\", \"p_email\": \"example@gmail.com\", \"p_phone\": \"09123456789\", \"p_start\": \"2026-03-26\", \"p_title\": \"Adaptive Capacity Of Different Varieties and Establishment Methods As Means Of Tecnological Adaptation To Rainfed Rice Production In Camiling, Tarlac\", \"p11_ifno\": \"\", \"p21_ifno\": \"\", \"p24_ifno\": \"\", \"p2_ifyes\": \"\", \"p_course\": \"\", \"p_origin\": \"Native – indigenous plants, adapted to local soils and climate\", \"p_reason\": \"111\", \"p_source\": \"111\", \"p18_ifyes\": \"\", \"p19_ifyes\": \"\", \"p20_ifyes\": \"\", \"p25_ifyes\": \"\", \"p29_ifyes\": \"\", \"p30_ifyes\": \"\", \"p35_ifyes\": \"\", \"p_adviser\": \"JOYCE ANNE O. MANUEL\", \"p_members\": \"Regine G. Batin, Desiree Joi D. Duque, Jhanny D. Tejada, Jhon Carlo G. Valdez\", \"p_species\": \"`11\", \"p_duration\": \"\", \"p_common_en\": \"111\", \"p_objective\": \"\", \"p_principal\": \"Desiree Joi D. Duque\", \"p_background\": \"111\", \"p_toxic_docs\": \"111\", \"queue_number\": \"UREO-0003\", \"submitted_at\": \"2026-05-26 10:14:30\", \"p_affiliation\": \"College of Agriculture and Forestry\", \"p_methodology\": \"111\", \"p_non_lc_docs\": \"111\", \"classification\": \"plant\", \"p_common_local\": \"111\", \"p_conservation\": \"NT – Near Threatened\", \"p_adviser_email\": \"example1@gmail.com\", \"p_adviser_phone\": \"09123456789\", \"p_invasive_docs\": \"111\", \"p_scientific_name\": \"111\", \"p_biodiversity_docs\": \"111\", \"p_adviser_affiliation\": \"Tarlac Agricultural University\"}','2026-05-26 02:14:30',1,0,NULL,0,0,NULL),(31,'UREO-0004','qf01','{\"email\": \"\", \"phone\": \"\", \"it_use\": \"☐\", \"funding\": \"\", \"members\": \"\", \"duration\": \"6 months\", \"end_date\": \"2026-06-10\", \"location\": \"\", \"food_tech\": \"☐\", \"human_use\": \"☑\", \"plant_use\": \"☐\", \"review_no\": \"☐\", \"department\": \"\", \"human_role\": \"\", \"review_yes\": \"☐\", \"start_date\": \"2026-01-01\", \"attached_cv\": \"☐\", \"date_filled\": \"\", \"date_signed\": \"\", \"engineering\": \"☐\", \"adviser_name\": \"\", \"exec_summary\": \"\", \"microbio_use\": \"☐\", \"adviser_email\": \"\", \"justification\": \"\", \"pilot_or_part\": \"\", \"project_title\": \"Test\", \"review_status\": \"\", \"animal_welfare\": \"☐\", \"principal_name\": \"Robertlyn Geil Soriano\", \"requestor_name\": \"\", \"attached_outline\": \"☐\", \"problem_objectives\": \"\", \"attached_other_forms\": \"☐\", \"attached_consent_form\": \"☐\", \"attached_category_form\": \"☐\", \"data_collection_analysis\": \"\"}','2026-06-10 14:27:00',1,0,NULL,0,0,NULL);
