INSERT INTO `system_messages` VALUES (13,'UREO-0001','acknowledgment','TAU-REO: Application Requirements','Greetings from TAU-REO!\r\n\r\nPlease read the general guidelines for research ethics review and evaluation. Then, kindly accomplish the following documents:\r\n\r\n✓ Application form TAU-REO-QF-01 (see attached file)\r\n✓ Research Ethics Review Category Form TAU-REO-QF-02 (see attached file)\r\n✓ CV of proponents\r\n✓ Research proposal/Thesis/Dissertation Outline\r\n\r\nSend the digital copy of the fully accomplished documents through this portal. As you upload the requirements, please ensure all forms are properly filled and signed. Thank you.\r\n\r\nPlease take note of the following:\r\n\r\n* Do not change the format and font style of the ISO registered forms\r\n* Please fill out the forms completely before uploading\r\n* Please be guided with our process cycle time (see the General Guidelines for more info). We process applications during working days only.\r\n\r\nBest regards,\r\nTAU-REO','2026-02-16 01:14:41',0,NULL),(14,'UREO-0002','acknowledgment','TAU-REO: Application Requirements','Greetings from TAU-REO!\r\n\r\nPlease read the general guidelines for research ethics review and evaluation. Then, kindly accomplish the following documents:\r\n\r\n✓ Application form TAU-REO-QF-01 (see attached file)\r\n✓ Research Ethics Review Category Form TAU-REO-QF-02 (see attached file)\r\n✓ CV of proponents\r\n✓ Research proposal/Thesis/Dissertation Outline\r\n\r\nSend the digital copy of the fully accomplished documents through this portal. As you upload the requirements, please ensure all forms are properly filled and signed. Thank you.\r\n\r\nPlease take note of the following:\r\n\r\n* Do not change the format and font style of the ISO registered forms\r\n* Please fill out the forms completely before uploading\r\n* Please be guided with our process cycle time (see the General Guidelines for more info). We process applications during working days only.\r\n\r\nBest regards,\r\nTAU-REO','2026-02-16 03:21:56',0,NULL),(15,'UREO-0003','acknowledgment','TAU-REO: Application Requirements','Greetings from TAU-REO!\r\n\r\nPlease read the general guidelines for research ethics review and evaluation. Then, kindly accomplish the following documents:\r\n\r\n✓ Application form TAU-REO-QF-01 (see attached file)\r\n✓ Research Ethics Review Category Form TAU-REO-QF-02 (see attached file)\r\n✓ CV of proponents\r\n✓ Research proposal/Thesis/Dissertation Outline\r\n\r\nSend the digital copy of the fully accomplished documents through this portal. As you upload the requirements, please ensure all forms are properly filled and signed. Thank you.\r\n\r\nPlease take note of the following:\r\n\r\n* Do not change the format and font style of the ISO registered forms\r\n* Please fill out the forms completely before uploading\r\n* Please be guided with our process cycle time (see the General Guidelines for more info). We process applications during working days only.\r\n\r\nBest regards,\r\nTAU-REO','2026-02-20 06:33:42',0,NULL),(16,'UREO-0001','requirement','Category Forms Required - UREO-0001','Application UREO-0001 requires Human category forms for Expedited review.\n\nApplicant: Allen John C. Agcang\nCategory: Human\nReview Type: Expedited','2026-03-24 08:39:49',0,NULL),(17,'UREO-0002','approval','Exempt Review Application - UREO-0002','Application UREO-0002 has been approved for Exempt Review and is ready for UREC Manager (Head) assignment.\n\nApplicant: PRINCESS T. CABENTA\nResearch Title: DETECTION OF HEARTWORM (Dirofilaria immitis) IN DOGS USING RAPID IMMUNOCHROMATOGRAPHIC ASSAY (CHW Ag) AT BARANGAY SAPANG MARAGUL, TARLAC CITY\n\nNote: This application does not require a research checklist and should be assigned directly to a UREC member or handled by the Manager.','2026-03-26 00:18:26',0,NULL),(18,'UREO-0001','requirement','Category Forms Required - UREO-0001','Application UREO-0001 requires Human category forms for Expedited review.\n\nAttached to your email is the annotated QF-02 with remarks and the guidelines for your classification.\nCategory: Human\nReview Type: Expedited','2026-03-26 05:33:42',0,NULL),(19,'UREO-0001','requirement','Category Forms Required - UREO-0001','Application UREO-0001 requires Human category forms for Expedited review.\n\nAttached to your email is the annotated QF-02 with remarks and the guidelines for your classification.\nCategory: Human\nReview Type: Expedited','2026-04-07 07:52:45',0,NULL),(20,'UREO-0001','update','Staff Feedback on QF02','Staff has provided new feedback on your QF02 form at 2026-04-21 08:29:38. Please review the remarks in your portal and address any concerns.','2026-04-21 00:29:39',0,NULL),(21,'UREO-0004','acknowledgment','TAU-REO: Application Requirements','Greetings from TAU-REO!\r\n\r\nPlease read the general guidelines for research ethics review and evaluation. Then, kindly accomplish the following documents:\r\n\r\n✓ Application form TAU-REO-QF-01 (see attached file)\r\n✓ Research Ethics Review Category Form TAU-REO-QF-02 (see attached file)\r\n✓ CV of proponents\r\n✓ Research proposal/Thesis/Dissertation Outline\r\n\r\nSend the digital copy of the fully accomplished documents through this portal. As you upload the requirements, please ensure all forms are properly filled and signed. Thank you.\r\n\r\nPlease take note of the following:\r\n\r\n* Do not change the format and font style of the ISO registered forms\r\n* Please fill out the forms completely before uploading\r\n* Please be guided with our process cycle time (see the General Guidelines for more info). We process applications during working days only.\r\n\r\nBest regards,\r\nTAU-REO','2026-05-19 03:55:16',0,NULL),(22,'UREO-0003','approval','Exempt Review Application - UREO-0003','Application UREO-0003 has been approved for Exempt Review and is ready for UREC Manager (Head) assignment.\n\nApplicant: Desiree Joi D. Duque\nResearch Title: Adaptive Capacity Of Different Varieties and Establishment Methods As Means Of Tecnological Adaptation To Rainfed Rice Production In Camiling, Tarlac\n\nNote: This application does not require a research checklist and should be assigned directly to a UREC member or handled by the Manager.','2026-05-26 03:27:33',0,NULL);
